namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int TotalRating { get; set; }
    public int RatingCount { get; set; }

    public double AverageRating => RatingCount > 0 ? (double)TotalRating / RatingCount : 0;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple and delicious pizza with fresh mozzarella and basil.",
            Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
            Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil."
        },
        new Recipe
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta with eggs, cheese, and pancetta.",
            Ingredients = "Spaghetti\nPancetta\nEggs\nPecorino Romano\nBlack pepper",
            Steps = "1. Cook spaghetti in salted boiling water.\n2. Fry pancetta until crispy.\n3. Whisk eggs with grated Pecorino and pepper.\n4. Toss hot pasta with pancetta.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra cheese."
        },
        new Recipe
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
            Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nOnion\nGarlic\nGinger",
            Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 minutes.\n5. Stir in cream and add chicken.\n6. Serve over basmati rice."
        },
        new Recipe
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
            Description = "Sweet, sour, and savory Thai noodles with crunchy vegetables.",
            Ingredients = "Rice noodles\nTofu\nBean sprouts\nCarrot\nGreen onion\nPeanuts\nTamarind paste\nFish sauce\nLime\nChili flakes",
            Steps = "1. Soak rice noodles in warm water for 30 minutes.\n2. Press and cube tofu, fry until golden.\n3. Mix tamarind paste, fish sauce, sugar, and lime juice.\n4. Stir-fry vegetables for 2 minutes.\n5. Add noodles and sauce, toss until coated.\n6. Top with peanuts and bean sprouts."
        },
        new Recipe
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
            Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
            Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Fill tortillas with seasoned beef.\n5. Top with lettuce, tomato, cheese, sour cream, and salsa."
        },
        new Recipe
        {
            Id = 6, Title = "Chocolate Chip Cookies", Category = "Desserts",
            Description = "Classic chewy cookies with melty chocolate chips.",
            Ingredients = "Butter\nSugar\nBrown sugar\nEggs\nVanilla extract\nFlour\nBaking soda\nSalt\nChocolate chips",
            Steps = "1. Cream butter and sugars until fluffy.\n2. Beat in eggs and vanilla.\n3. Mix flour, baking soda, and salt, then combine with wet ingredients.\n4. Fold in chocolate chips.\n5. Scoop onto baking sheet.\n6. Bake at 375°F (190°C) for 9-11 minutes."
        }
    };

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe != null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRating += stars;
            recipe.RatingCount++;
        }
    }
}

