@page "/recipes/{Category}"
@inject RecipeService RecipeService

<PageTitle>@Category Recipes - RecipeShare</PageTitle>

<h1>@Category Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        @if (recipe.RatingCount > 0)
                        {
                            <p class="text-muted">⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</p>
                        }
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string Category { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> recipes = Array.Empty<Recipe>();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe == null)
{
    <p>Recipe not found.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/recipes/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <div class="row">
        <div class="col-md-4">
            <h3>Ingredients</h3>
            <ul class="list-group mb-3">
                @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>
        </div>
        <div class="col-md-8">
            <h3>Steps</h3>
            @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step</p>
            }
        </div>
    </div>

    <hr />
    <h3>Rate this Recipe</h3>
    <StarRating RecipeId="recipe.Id" />
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => Rate(star)"
                disabled="@hasRated"
                title="Rate @star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </button>
    }
    @if (hasRated)
    {
        <span class="text-success ms-2">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int currentRating;
    private bool hasRated;

    private void Rate(int stars)
    {
        if (hasRated) return;
        currentRating = stars;
        hasRated = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the collection.
        <a href="/recipe/@submittedId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="5" placeholder="1 cup flour&#10;2 eggs&#10;..." />
            <ValidationMessage For="() => model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="6" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;..." />
            <ValidationMessage For="() => model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;
    private int submittedId;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Description = $"A community recipe for {model.Title}.",
            Ingredients = model.Ingredients,
            Steps = model.Steps
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

